function onStart() {
  this.rigidbody.velocityY = 120;
  var label = this.x < -100 ? 'Dynamic' : (this.x > 100 ? 'Kinematic' : 'Static');
  console.log('[KinematicCapsule vs ' + label + '] falling, testing collision...');
}

function onCollisionEnter(other) {
  var label = this.x < -100 ? 'Dynamic' : (this.x > 100 ? 'Kinematic' : 'Static');
  console.log('[KinematicCapsule vs ' + label + '] COLLISION ENTER — collision fix confirmed working!');
  this.sprite.color = '#22c55e';
  this.rigidbody.velocityY = 0;
}

function onCollisionExit(other) {
  var label = this.x < -100 ? 'Dynamic' : (this.x > 100 ? 'Kinematic' : 'Static');
  console.log('[KinematicCapsule vs ' + label + '] collision exit');
}

function onCollisionEnter(other) {
  console.log('[DynamicBox] hit by kinematic capsule');
  this.sprite.color = '#22c55e';
}

